#include <stdio.h>
#include <sys/mman.h>
#include <unistd.h>
#include <string.h>

int main(void) {
    size_t huge = 1UL << 30; /* 1 GB */
    char *mem = (char *)mmap(NULL, huge,
        PROT_READ | PROT_WRITE,
        MAP_PRIVATE | ____, -1, 0);
    if (mem == MAP_FAILED) { perror("mmap"); return 1; }
    printf("Mapped 1GB: success\n");
    size_t ps = (size_t)getpagesize();
    mem[0] = 'A';
    mem[ps] = 'B';
    mem[ps * 2] = 'C';
    printf("Touched 3 pages: %c%c%c\n", mem[0], mem[ps], mem[ps * 2]);
    unsigned char vec[3];
    int rc = ____(mem, ps * 3, vec);
    printf("mincore result: %d\n", rc);
    int resident = 0;
    for (int i = 0; i < 3; i++) {
        if (vec[i] & 1) resident++;
    }
    printf("Resident pages: %d/3\n", resident);
    printf("Overcommit: %s\n", resident <= 3 ? "yes" : "no");
    ____(mem, huge);
    return 0;
}

