void example_madvise(void) {
    size_t ps = (size_t)getpagesize();
    char *p = mmap(NULL, ps*10, PROT_READ|PROT_WRITE, MAP_PRIVATE|MAP_ANONYMOUS, -1, 0);
    madvise(p, ps*10, MADV_SEQUENTIAL);
    p[0] = 'X';
    printf("madvise + touch: ok\n");
    munmap(p, ps*10);
